#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

Node* createNode(int data) {
    Node* nd = (Node*)malloc(sizeof(Node));
    nd->data = data;
    nd->next = NULL;
    return nd;
}

void insertAfterK(Node** head, int value, int k) {
    Node* newNode = createNode(value);
    Node* cur = *head;
    for (int i = 1; i < k && cur != NULL; ++i) {
        cur = cur->next;
    }
    if (cur == NULL) { // should not happen with valid k
        free(newNode);
        return;
    }
    newNode->next = cur->next;
    cur->next = newNode;
}

void printList(Node* head) {
    while (head) {
        printf("%d", head->data);
        if (head->next) printf(" ");
        head = head->next;
    }
    printf("\n");
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int x, k; scanf("%d %d", &x, &k);
        Node* head = NULL; Node* tail = NULL;
        for (int i = 0; i < n; ++i) {
            int val; scanf("%d", &val);
            Node* nd = createNode(val);
            if (!head) head = tail = nd;
            else { tail->next = nd; tail = nd; }
        }
        insertAfterK(&head, x, k);
        printList(head);
        // free memory (optional for contest)
        Node* tmp;
        while (head) { tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

