#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int d): data(d), next(nullptr) {}
};

void insertAfterK(Node** head, int value, int k) {
    Node* newNode = new Node(value);
    Node* cur = *head;
    for (int i = 1; i < k && cur != nullptr; ++i) cur = cur->next;
    if (!cur) { delete newNode; return; }
    newNode->next = cur->next;
    cur->next = newNode;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int n; cin>>n;
        int x,k; cin>>x>>k;
        Node* head=nullptr; Node* tail=nullptr;
        for(int i=0;i<n;++i){
            int v;cin>>v;
            Node* nd=new Node(v);
            if(!head) head=tail=nd; else {tail->next=nd; tail=nd;}
        }
        insertAfterK(&head,x,k);
        for(Node* cur=head; cur; cur=cur->next){
            cout<<cur->data;
            if(cur->next) cout<<' ';
        }
        cout<<"\n";
        // free list
        while(head){Node* tmp=head;head=head->next;delete tmp;}
    }
    return 0;
}

