import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int data;
        Node next;
        Node(int d){ data=d; next=null; }
    }

    static void insertAfterK(Node head, int value, int k) {
        Node newNode = new Node(value);
        Node cur = head;
        for (int i = 1; i < k && cur != null; i++) {
            cur = cur.next;
        }
        if (cur == null) return; // should not happen
        newNode.next = cur.next;
        cur.next = newNode;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int n = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            int x = Integer.parseInt(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            Node head = null, tail = null;
            for (int i = 0; i < n; i++) {
                int val = Integer.parseInt(st.nextToken());
                Node nd = new Node(val);
                if (head == null) head = tail = nd;
                else { tail.next = nd; tail = nd; }
            }
            insertAfterK(head, x, k);
            for (Node cur = head; cur != null; cur = cur.next) {
                out.append(cur.data);
                if (cur.next != null) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

