#!/usr/bin/env python3
import sys

def create_node(val):
    return [val, None]  # [data, next]

def insert_after_k(head, value, k):
    new_node = create_node(value)
    cur = head
    for _ in range(k-1):
        if cur is None:
            break
        cur = cur[1]
    if cur is None:
        return head
    new_node[1] = cur[1]
    cur[1] = new_node
    return head

def list_to_values(head):
    vals = []
    while head:
        vals.append(str(head[0]))
        head = head[1]
    return ' '.join(vals)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        x = int(next(it))
        k = int(next(it))
        head = None
        tail = None
        for _ in range(n):
            val = int(next(it))
            node = create_node(val)
            if head is None:
                head = tail = node
            else:
                tail[1] = node
                tail = node
        head = insert_after_k(head, x, k)
        out_lines.append(list_to_values(head))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

